#include <bits/stdc++.h>
using namespace std;
int dp[3003][3003],idx[3003][3003],idy[3003][3003];
string s,t;
void f(int x,int y){
	if(dp[x][y]>1 || (dp[x][y]==1 && s[x]!=t[y]))f(idx[x][y],idy[x][y]);
	if(s[x]==t[y])cout<<s[x];
}
int main(){
    cin>>s>>t;
    cout<<endl;
    return 0;
}
